"""Process-local TTL cache for onboarding inbox scans, keyed by (user_id, fmt)."""

import time

_TTL_SECONDS = 300.0

_cache: dict[tuple[str, str], tuple[float, list[dict]]] = {}


def get(user_id: str, fmt: str) -> list[dict] | None:
    key = (user_id, fmt)
    entry = _cache.get(key)
    if entry is None:
        return None
    ts, emails = entry
    if time.monotonic() - ts > _TTL_SECONDS:
        _cache.pop(key, None)
        return None
    return emails


def put(user_id: str, fmt: str, emails: list[dict]) -> None:
    if not emails:
        return
    _cache[(user_id, fmt)] = (time.monotonic(), emails)


def invalidate(user_id: str) -> None:
    for key in [k for k in _cache if k[0] == user_id]:
        _cache.pop(key, None)

